import{_ as e,c as r,o as i,ae as a}from"./chunks/framework.CDjunVez.js";const f=JSON.parse('{"title":"Shopify BFCM 2024：電商平台如何把購物節變成技術力展演","description":"Shopify 在 2024 年黑色星期五創下 115 億美元銷售額，但更值得關注的是他們如何用 Las Vegas Sphere、3D 互動體驗和 VR 技術，把購物節變成一場技術實力的全球宣傳。","frontmatter":{"title":"Shopify BFCM 2024：電商平台如何把購物節變成技術力展演","description":"Shopify 在 2024 年黑色星期五創下 115 億美元銷售額，但更值得關注的是他們如何用 Las Vegas Sphere、3D 互動體驗和 VR 技術，把購物節變成一場技術實力的全球宣傳。","date":"2024-11-29T00:00:00.000Z","author":"Clement Tang","tags":["Shopify","BFCM","電商","技術行銷","數據視覺化"],"category":"articles","status":"published","lastModified":"2026-01-27T00:00:00.000Z"},"headers":[],"relativePath":"articles/2024-11-29-shopify-bfcm-2024-campaigns.md","filePath":"articles/2024-11-29-shopify-bfcm-2024-campaigns.md"}'),l={name:"articles/2024-11-29-shopify-bfcm-2024-campaigns.md"};function o(s,t,h,n,p,d){return i(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="shopify-bfcm-2024-電商平台如何把購物節變成技術力展演" tabindex="-1">Shopify BFCM 2024：電商平台如何把購物節變成技術力展演 <a class="header-anchor" href="#shopify-bfcm-2024-電商平台如何把購物節變成技術力展演" aria-label="Permalink to &quot;Shopify BFCM 2024：電商平台如何把購物節變成技術力展演&quot;">​</a></h1><blockquote><p>Shopify 在 2024 年黑色星期五創下 115 億美元銷售額，但更值得關注的是他們如何用 Las Vegas Sphere、3D 互動體驗和 VR 技術，把購物節變成一場技術實力的全球宣傳。</p></blockquote><hr><h2 id="the-big-picture" tabindex="-1">The Big Picture <a class="header-anchor" href="#the-big-picture" aria-label="Permalink to &quot;The Big Picture&quot;">​</a></h2><p>當其他電商平台還在比較銷售數字時，Shopify 選擇了一條不同的路：<strong>把 BFCM 變成技術力的全球展演</strong>。</p><p>2024 年黑五週末，Shopify 史無前例地在 Las Vegas Sphere——世界最大數位展示螢幕——即時播放全球銷售數據。同時推出瀏覽器 3D 駕駛艙體驗、VR/AR 沉浸式應用，讓「看數據」變成一場視覺盛宴。</p><p>這不只是行銷活動，而是 Shopify 重新定義自己的宣言：<strong>我們不只是電商平台，我們是商務作業系統（Commerce Operating System）</strong>。</p><hr><h2 id="why-it-matters" tabindex="-1">Why It Matters <a class="header-anchor" href="#why-it-matters" aria-label="Permalink to &quot;Why It Matters&quot;">​</a></h2><p><strong>對電商產業而言</strong>：Shopify 正在改變平台競爭的維度。當 Amazon 專注於物流、阿里巴巴強調生態系時，Shopify 選擇展示技術創新能力，吸引的是重視品牌獨立性的商家。</p><p><strong>對技術從業者而言</strong>：這些活動展示了即時數據視覺化、瀏覽器 3D 渲染、VR/AR 整合的前沿應用，是學習現代 Web 技術的絕佳案例。</p><p><strong>對行銷人員而言</strong>：Shopify 示範了如何把「後台數據」變成「前台故事」，用技術能力建立品牌認知。</p><hr><h2 id="主要活動項目" tabindex="-1">主要活動項目 <a class="header-anchor" href="#主要活動項目" aria-label="Permalink to &quot;主要活動項目&quot;">​</a></h2><h3 id="_1-las-vegas-sphere-即時數據展示" tabindex="-1">1. Las Vegas Sphere 即時數據展示 <a class="header-anchor" href="#_1-las-vegas-sphere-即時數據展示" aria-label="Permalink to &quot;1. Las Vegas Sphere 即時數據展示&quot;">​</a></h3><p><strong>史上首次在 Sphere 播放即時銷售數據</strong></p><ul><li><strong>地點</strong>：Las Vegas Sphere（世界最大數位展示螢幕）</li><li><strong>技術</strong>：採用 Unreal Engine 即時渲染</li><li><strong>內容</strong>： <ul><li>即時視覺化全球銷售數據</li><li>點對點訂單弧線動畫（從訂單產生地到配送地）</li><li>每當商家達成首筆銷售時播放煙火特效</li></ul></li><li><strong>時間</strong>：Black Friday 週末期間（2024/11/29 宣布）</li><li><strong>宣布者</strong>：Shopify CEO Tobi Lütke</li></ul><h3 id="_2-bfcm-live-globe-mothership-3d-互動體驗" tabindex="-1">2. BFCM Live Globe Mothership 3D 互動體驗 <a class="header-anchor" href="#_2-bfcm-live-globe-mothership-3d-互動體驗" aria-label="Permalink to &quot;2. BFCM Live Globe Mothership 3D 互動體驗&quot;">​</a></h3><p><strong>全瀏覽器 3D 駕駛艙體驗</strong></p><ul><li><strong>網址</strong>：<a href="https://bfcm.shopify.com" target="_blank" rel="noreferrer">https://bfcm.shopify.com</a></li><li><strong>技術架構</strong>： <ul><li>Three.js 和 React-three-fiber</li><li>完全基於瀏覽器的 3D 渲染</li><li>貝茲曲線（Bézier curves）和三次 Hermite 樣條曲線</li></ul></li><li><strong>互動功能</strong>： <ul><li>🎹 <strong>內建音樂合成器</strong>：將全球即時銷售轉換為音樂</li><li>🌍 <strong>Live Globe 地球儀</strong>：可互動操控</li><li>⚙️ <strong>重力開關</strong>：關閉重力觀察物理系統運作</li><li>🎮 <strong>多種互動控制項</strong>：包含 MIDI 鍵盤、Shoppy 吉祥物搖頭娃娃等</li></ul></li><li><strong>即時數據展示</strong>：每分鐘訂單數、熱門商品、Webhooks 數量、CDN 請求數</li></ul><h3 id="_3-vr-ar-沉浸式體驗" tabindex="-1">3. VR/AR 沉浸式體驗 <a class="header-anchor" href="#_3-vr-ar-沉浸式體驗" aria-label="Permalink to &quot;3. VR/AR 沉浸式體驗&quot;">​</a></h3><p><strong>支援最新 VR 裝置的全方位體驗</strong></p><ul><li><strong>支援裝置</strong>：Apple Vision Pro、Meta Quest 3/3S</li><li><strong>體驗內容</strong>： <ul><li>完全沉浸式的 Live Globe 環境</li><li>即時銷售數據視覺化</li><li>可在虛擬空間中操控各項數據</li></ul></li></ul><h3 id="_4-技術基礎設施成就" tabindex="-1">4. 技術基礎設施成就 <a class="header-anchor" href="#_4-技術基礎設施成就" aria-label="Permalink to &quot;4. 技術基礎設施成就&quot;">​</a></h3><p><strong>BFCM 2024 關鍵數據</strong></p><table tabindex="0"><thead><tr><th>類別</th><th>數據</th></tr></thead><tbody><tr><td>總銷售額</td><td>$115 億美元（年增 24%）</td></tr><tr><td>購買人數</td><td>7,600 萬人（年增 25%）</td></tr><tr><td>商家紀錄</td><td>67,000+ 家創下歷史最高單日銷售</td></tr><tr><td>新創業家</td><td>16,500+ 人達成首筆銷售</td></tr><tr><td>平均購物車</td><td>$108.56</td></tr></tbody></table><p><strong>技術處理量</strong></p><table tabindex="0"><thead><tr><th>指標</th><th>數據</th></tr></thead><tbody><tr><td>資料處理</td><td>57.3 PB</td></tr><tr><td>資料庫查詢</td><td>10.5 兆次</td></tr><tr><td>邊緣請求</td><td>1.19 兆次</td></tr><tr><td>資料庫寫入</td><td>1.17 兆次</td></tr></tbody></table><hr><h2 id="技術關鍵字" tabindex="-1">技術關鍵字 <a class="header-anchor" href="#技術關鍵字" aria-label="Permalink to &quot;技術關鍵字&quot;">​</a></h2><ul><li>Unreal Engine（即時渲染）</li><li>Three.js / React-three-fiber（瀏覽器 3D）</li><li>即時數據視覺化</li><li>VR/AR 商務應用</li><li>音樂合成器（數據轉音效）</li><li>物理引擎</li><li>WebGL / WebXR</li></ul><hr><h2 id="what-s-next" tabindex="-1">What&#39;s Next <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s Next&quot;">​</a></h2><p><strong>值得關注的發展：</strong></p><ul><li><strong>即時數據視覺化成為標配</strong>：預期更多平台會投資類似的即時展示能力</li><li><strong>VR/AR 電商體驗</strong>：Apple Vision Pro 和 Meta Quest 的普及將推動更多沉浸式購物體驗</li><li><strong>技術行銷的興起</strong>：B2B 平台將更重視用技術能力建立品牌認知</li></ul><p><strong>給從業者的建議：</strong></p><ul><li>研究 Shopify Engineering Blog 了解大規模即時系統設計</li><li>嘗試 Three.js 和 React-three-fiber 建立互動式數據視覺化</li><li>關注 WebXR 標準發展，為 VR/AR 整合做準備</li></ul><hr><h2 id="參考資料" tabindex="-1">參考資料 <a class="header-anchor" href="#參考資料" aria-label="Permalink to &quot;參考資料&quot;">​</a></h2><ul><li><a href="https://www.shopify.com/news/live-globe-2024" target="_blank" rel="noreferrer">Shopify Official News - Live Globe 2024</a> - 官方發布</li><li><a href="https://shopify.engineering/how-we-built-shopifys-bfcm-2023-globe" target="_blank" rel="noreferrer">How We Built the BFCM 2023 Globe</a> - Shopify Engineering</li><li><a href="https://newsletter.pragmaticengineer.com/p/shopify-black-friday" target="_blank" rel="noreferrer">How Shopify Built Its Live Globe for Black Friday</a> - Pragmatic Engineer</li><li><a href="https://www.valueaddedresource.net/shopify-black-friday-las-vegas-sphere/" target="_blank" rel="noreferrer">Shopify Makes Black Friday History With Las Vegas Sphere</a> - Value Added Resource</li><li><a href="https://x.com/tobi/status/1863935229620363693" target="_blank" rel="noreferrer">Tobi Lütke BFCM 2024 announcement</a> - Twitter/X</li></ul><hr>',41)])])}const c=e(l,[["render",o]]);export{f as __pageData,c as default};
